import{_ as e,o as a,c as l,ae as o}from"./chunks/framework.DAK3ioSj.js";const g=JSON.parse('{"title":"Skill 执行（Execution）","description":"","frontmatter":{},"headers":[],"relativePath":"radar/category-03-execution.md","filePath":"radar/category-03-execution.md"}'),r={name:"radar/category-03-execution.md"};function n(i,t,s,d,h,k){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="skill-执行-execution" tabindex="-1">Skill 执行（Execution） <a class="header-anchor" href="#skill-执行-execution" aria-label="Permalink to &quot;Skill 执行（Execution）&quot;">​</a></h1><blockquote><p><strong>成熟度</strong>: 🟡 成长期 · <strong>综合评分</strong>: <strong>0.45</strong></p><p><strong>业界判断</strong>：<strong>SkCC（SkIR 强类型 IR）</strong> 刚刚填补了&quot;跨框架可移植性&quot;这一历史空白，但 SkillsBench 揭示的 <strong>16/84 负增益 + 跨领域增益从 +4.5pp 到 +51.9pp 的差异</strong>仍无方案。</p></blockquote><hr><h2 id="业界代表产品" tabindex="-1">业界代表产品 <a class="header-anchor" href="#业界代表产品" aria-label="Permalink to &quot;业界代表产品&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产品</th><th>来源</th><th>核心路径</th><th>关键数字</th></tr></thead><tbody><tr><td><a href="./tech-openspace.html">OpenSpace</a></td><td>HKU (<strong>6.1K+ ★</strong>)</td><td>MCP Server 即插即用</td><td>220 任务 40.8% → 70.8%</td></tr><tr><td><a href="./tech-agentskillos.html">AgentSkillOS</a></td><td>学术</td><td>DAG 并行 / 串行编排</td><td>30 任务 5 类基准</td></tr><tr><td><a href="./tech-memento-skills.html">Memento-Skills</a></td><td>学术 (1.4K+ ★)</td><td>Read→Execute→Reflect→Write</td><td>GAIA +26.2% / HLE +116.2%</td></tr><tr><td><strong><a href="./tech-skcc.html">SkCC</a></strong> ★</td><td>学术</td><td>SkIR 强类型 IR 跨框架编译</td><td><strong>Claude Code 21.1% → 33.3% · Kimi CLI 35.1% → 48.7%</strong></td></tr></tbody></table><hr><h2 id="行业核心痛点" tabindex="-1">行业核心痛点 <a class="header-anchor" href="#行业核心痛点" aria-label="Permalink to &quot;行业核心痛点&quot;">​</a></h2><h3 id="🔴-同一-skill-跨场景效果差异-10×" tabindex="-1">🔴 同一 Skill 跨场景效果差异 10× <a class="header-anchor" href="#🔴-同一-skill-跨场景效果差异-10×" aria-label="Permalink to &quot;🔴 同一 Skill 跨场景效果差异 10×&quot;">​</a></h3><p>同类 Skill 在不同领域增益<strong>从 +4.5pp（软件工程）到 +51.9pp（医疗）不等</strong>。使用者在安装一个 Skill 之前<strong>完全无法预判</strong>它在自己的场景上会是正增益还是负增益。</p><blockquote><p><strong>没有任何工具能做&quot;Skill - 场景适配度预测&quot;</strong>。SkillNet 的 5 维评分评估的是 Skill 内在质量，不是场景适配度。</p></blockquote><h3 id="🔴-负增益-加-skill-反而更差" tabindex="-1">🔴 负增益（加 Skill 反而更差） <a class="header-anchor" href="#🔴-负增益-加-skill-反而更差" aria-label="Permalink to &quot;🔴 负增益（加 Skill 反而更差）&quot;">​</a></h3><p>SkillsBench 84 个任务中 <strong>16 个出现负增益</strong> —— Skill 不仅无效反而有害。更糟的是只做 pass/fail 结果评测，<strong>无法判断失败原因</strong>：是 Agent 忽略了 Skill？是 Skill 本身有缺陷？是选错了 Skill？</p><h3 id="🟡-跨-agent-框架行为不一致-skcc-已破局" tabindex="-1">🟡 跨 Agent 框架行为不一致（SkCC 已破局） <a class="header-anchor" href="#🟡-跨-agent-框架行为不一致-skcc-已破局" aria-label="Permalink to &quot;🟡 跨 Agent 框架行为不一致（SkCC 已破局）&quot;">​</a></h3><p>历史上<strong>完全空白</strong> —— 同一个 Skill 在 Claude Code 和 OpenCode 上即使格式兼容，执行行为也可能完全不同。Agent Skills 标准只解决&quot;格式兼容&quot;而非&quot;行为一致性&quot;。</p><p><strong>2026-05 SkCC 论文</strong>首次提出 <strong>SkIR 强类型 IR</strong>，把 Skill 语义与框架格式解耦，实证 Claude Code 21.1% → 33.3%、Kimi CLI 35.1% → 48.7%。但仍是学术阶段，未见生产部署。</p><h3 id="🟡-跨模型迁移效果不一致" tabindex="-1">🟡 跨模型迁移效果不一致 <a class="header-anchor" href="#🟡-跨模型迁移效果不一致" aria-label="Permalink to &quot;🟡 跨模型迁移效果不一致&quot;">​</a></h3><p>EvoSkills 跨模型实验证明差异确实存在 —— 同一 Skill 在不同模型上效果差异 <strong>+36pp 到 +44pp</strong>。但这些研究都是&quot;发现差异存在&quot;，<strong>没有产品提供持续的模型切换后效果监测</strong>。</p><h3 id="⚪-多-skill-组合执行的失败回滚" tabindex="-1">⚪ 多 Skill 组合执行的失败回滚 <a class="header-anchor" href="#⚪-多-skill-组合执行的失败回滚" aria-label="Permalink to &quot;⚪ 多 Skill 组合执行的失败回滚&quot;">​</a></h3><p>一个任务串联三个 Skill，中间某一步失败了整个任务就崩了，<strong>不知道从哪恢复</strong>。AgentSkillOS 的 DAG 定义了执行顺序，但不涉及失败后的回滚和恢复策略。<strong>无专门研究</strong>。</p>',19)])])}const u=e(r,[["render",n]]);export{g as __pageData,u as default};
